import Foundation

struct CategoryContent7 {
    static let aiHealthcare = CategoryData(
        id: "ai_healthcare", name: "AI Helping People", icon: "heart.text.square", colorName: "aiTeal",
        description: "How AI helps doctors, scientists, and patients",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 6,
        unlockRequirement: .completeCategoryMinimum("how_ai_learns")
    )
    static let lesson1 = LessonData(id: "ah_l1", title: "AI Medical Imaging", description: "AI reading X-rays and scans", categoryId: "ai_healthcare", questions: [
        Question(id: "ah1_q1", type: .multipleChoice, questionText: "What is the primary role of AI in medical imaging?", options: ["Detecting abnormalities in X-rays, MRIs, and CT scans", "Replacing radiologists in all clinical decisions", "Automating hospital billing and scheduling", "Manufacturing new imaging equipment"], correctAnswer: "Detecting abnormalities in X-rays, MRIs, and CT scans", explanation: "AI systems from companies like Google Health, Viz.ai, and Aidoc analyze medical images to flag tumors, fractures, and other conditions, often catching subtle findings humans might miss."),
        Question(id: "ah1_q2", type: .trueFalse, questionText: "Google Health's AI system demonstrated the ability to detect breast cancer in mammograms more accurately than individual radiologists in a 2020 study.", options: ["True", "False"], correctAnswer: "True", explanation: "A study published in Nature showed Google Health's AI reduced false positives by 5.7% and false negatives by 9.4% compared to individual radiologists reading mammograms."),
        Question(id: "ah1_q3", type: .fillInBlank, questionText: "Viz.ai uses artificial intelligence to detect large vessel __________ strokes from CT scans, alerting specialists within minutes.", options: ["occlusion", "hemorrhagic", "transient", "migraine"], correctAnswer: "occlusion", explanation: "Viz.ai's FDA-cleared platform detects large vessel occlusion strokes from CT angiography and automatically notifies neurointerventional specialists, dramatically reducing treatment times."),
        Question(id: "ah1_q4", type: .scenarioJudgment, questionText: "An AI system flags a suspicious area on a chest X-ray, but the radiologist believes it is a normal anatomical variant. What should happen next?", options: ["The radiologist should document the finding and investigate further", "The AI result should be permanently deleted from the record", "The patient should be immediately scheduled for surgery", "The hospital should stop using the AI system entirely"], correctAnswer: "The radiologist should document the finding and investigate further", explanation: "AI serves as a second reader. When AI and a radiologist disagree, best practice is to document both assessments and pursue additional investigation to ensure nothing is missed."),
        Question(id: "ah1_q5", type: .multipleChoice, questionText: "What advantage does AI bring to high-volume radiology departments?", options: ["Consistent analysis that does not degrade with fatigue or workload", "Elimination of the need for any imaging equipment", "Automatic generation of treatment prescriptions", "Reduced need for patient consent before scans"], correctAnswer: "Consistent analysis that does not degrade with fatigue or workload", explanation: "Unlike human radiologists who experience fatigue during long shifts, AI maintains the same level of analytical performance across thousands of images, helping prioritize urgent cases."),
        Question(id: "ah1_q6", type: .multipleChoice, questionText: "How is PathAI transforming the field of pathology?", options: ["Using deep learning to analyze tissue slides for signs of cancer and disease", "Replacing lab technicians with robotic arms", "Automating patient prescription refills", "Generating synthetic tissue samples for research"], correctAnswer: "Using deep learning to analyze tissue slides for signs of cancer and disease", explanation: "PathAI applies deep learning algorithms to digitized pathology slides, helping pathologists identify cellular abnormalities, grade tumors, and improve diagnostic accuracy in cancer detection.")
    ], order: 0, difficulty: .beginner)
    static let lesson2 = LessonData(id: "ah_l2", title: "AI Drug Discovery", description: "Accelerating medicine development", categoryId: "ai_healthcare", questions: [
        Question(id: "ah2_q1", type: .multipleChoice, questionText: "How do companies like Insilico Medicine and Recursion Pharmaceuticals use AI in drug discovery?", options: ["Predicting which molecular compounds could become effective medicines", "Physically manufacturing and packaging pills", "Delivering medications directly to patient homes", "Setting insurance reimbursement rates for drugs"], correctAnswer: "Predicting which molecular compounds could become effective medicines", explanation: "AI platforms screen millions of molecular structures to predict drug candidates, dramatically reducing the time and cost of early-stage research compared to traditional methods."),
        Question(id: "ah2_q2", type: .trueFalse, questionText: "Insilico Medicine used AI to identify a novel drug candidate for idiopathic pulmonary fibrosis and advance it to clinical trials in under 30 months, a process that typically takes over four years.", options: ["True", "False"], correctAnswer: "True", explanation: "Insilico Medicine's AI platform identified both a novel target and a drug candidate for pulmonary fibrosis, reaching Phase I clinical trials in record time, demonstrating AI's potential to compress drug discovery timelines."),
        Question(id: "ah2_q3", type: .fillInBlank, questionText: "DeepMind's AlphaFold solved the protein __________ problem, predicting 3D structures for over 200 million proteins and revolutionizing biological research.", options: ["folding", "binding", "sequencing", "splicing"], correctAnswer: "folding", explanation: "AlphaFold predicts how amino acid chains fold into 3D protein structures, solving a 50-year grand challenge in biology. This breakthrough earned Demis Hassabis and John Jumper the 2024 Nobel Prize in Chemistry."),
        Question(id: "ah2_q4", type: .multipleChoice, questionText: "Why are graph neural networks particularly well-suited for analyzing molecular structures in drug discovery?", options: ["They naturally represent atoms as nodes and bonds as edges in molecular graphs", "They require less training data than any other approach", "They can only process simple tabular datasets", "They work exclusively with text-based chemical formulas"], correctAnswer: "They naturally represent atoms as nodes and bonds as edges in molecular graphs", explanation: "Graph neural networks model molecules as mathematical graphs where atoms are nodes and chemical bonds are edges, enabling deep learning to analyze complex molecular interactions and predict drug properties."),
        Question(id: "ah2_q5", type: .scenarioJudgment, questionText: "An AI platform identifies a promising new cancer drug compound with strong predicted efficacy. Should it be given directly to patients?", options: ["No, it must still go through rigorous clinical trials for safety and efficacy", "Yes, if the AI model has a high confidence score", "Only if the patient signs a waiver accepting the risk"], correctAnswer: "No, it must still go through rigorous clinical trials for safety and efficacy", explanation: "AI predictions accelerate discovery but cannot replace clinical validation. All drug candidates must pass Phase I, II, and III trials to verify safety and efficacy in real patients before approval."),
        Question(id: "ah2_q6", type: .multipleChoice, questionText: "How did BenevolentAI demonstrate the value of AI drug repurposing during the COVID-19 pandemic?", options: ["It identified baricitinib, an existing arthritis drug, as a potential COVID-19 treatment", "It manufactured new ventilators using machine learning", "It predicted the exact date the pandemic would end", "It created a new vaccine from scratch using only AI"], correctAnswer: "It identified baricitinib, an existing arthritis drug, as a potential COVID-19 treatment", explanation: "BenevolentAI's knowledge graph identified baricitinib as a candidate for treating COVID-19 by targeting both the virus entry mechanism and inflammatory response. The drug was later authorized for emergency use.")
    ], order: 1, difficulty: .intermediate)
    static let lesson3 = LessonData(id: "ah_l3", title: "AI Diagnostics", description: "AI helping doctors diagnose", categoryId: "ai_healthcare", questions: [
        Question(id: "ah3_q1", type: .multipleChoice, questionText: "How do AI diagnostic platforms like Ada Health and Babylon Health assist physicians?", options: ["Analyzing patient symptoms and medical history to suggest possible conditions", "Issuing legally binding medical diagnoses without physician review", "Automatically prescribing medications based on symptom input", "Replacing the need for medical education and residency training"], correctAnswer: "Analyzing patient symptoms and medical history to suggest possible conditions", explanation: "AI diagnostic platforms use symptom analysis and probabilistic reasoning to generate differential diagnoses, helping physicians consider conditions they might not have initially suspected."),
        Question(id: "ah3_q2", type: .trueFalse, questionText: "In most countries, AI systems are legally permitted to provide a final medical diagnosis without any physician involvement.", options: ["True", "False"], correctAnswer: "False", explanation: "Regulatory frameworks in most jurisdictions require a licensed physician to make final diagnostic decisions. AI tools are classified as clinical decision support and must be overseen by qualified medical professionals."),
        Question(id: "ah3_q3", type: .multipleChoice, questionText: "Google DeepMind's AI system for detecting eye diseases works by analyzing which type of medical data?", options: ["Optical coherence tomography scans of the retina", "Standard blood pressure measurements taken at home", "Patient-reported symptom questionnaires submitted online", "Audio recordings of patient heartbeat patterns"], correctAnswer: "Optical coherence tomography scans of the retina", explanation: "DeepMind partnered with Moorfields Eye Hospital to develop an AI that analyzes OCT retinal scans, detecting over 50 eye diseases including diabetic retinopathy and macular degeneration with expert-level accuracy."),
        Question(id: "ah3_q4", type: .fillInBlank, questionText: "AI-powered clinical __________ support systems integrate patient data, medical literature, and diagnostic algorithms to help physicians make evidence-based decisions.", options: ["decision", "treatment", "scheduling", "resource"], correctAnswer: "decision", explanation: "Clinical decision support systems use AI to synthesize patient data with medical knowledge bases, helping healthcare providers identify likely diagnoses and recommended next steps based on the latest evidence."),
        Question(id: "ah3_q5", type: .matchPairs, questionText: "Match these AI diagnostic tools with their specialties:", matchPairs: [
            MatchPair(term: "IDx-DR", definition: "Autonomous diabetic eye screening"),
            MatchPair(term: "AliveCor KardiaMobile", definition: "ECG heart rhythm analysis"),
            MatchPair(term: "SkinVision", definition: "Skin lesion risk assessment"),
            MatchPair(term: "Tempus", definition: "Genomic cancer profiling")
        ], explanation: "Various AI companies have developed specialized diagnostic tools targeting specific medical conditions, each using different types of patient data and AI approaches."),
        Question(id: "ah3_q6", type: .scenarioJudgment, questionText: "A patient uses an AI symptom-checking app that suggests they may have a serious cardiac condition. They feel anxious and unsure what to do next. What is the best course of action?", options: ["Schedule an appointment with a cardiologist for proper clinical evaluation", "Trust the app's assessment completely and begin self-treating", "Dismiss the result entirely since AI is never accurate", "Post the results on social media to get other opinions"], correctAnswer: "Schedule an appointment with a cardiologist for proper clinical evaluation", explanation: "AI symptom checkers are screening tools, not diagnostic instruments. A concerning result should prompt a visit to a qualified specialist who can perform proper examinations and diagnostic tests.")
    ], order: 2, difficulty: .intermediate)
    static let lesson4 = LessonData(id: "ah_l4", title: "Patient Data Privacy", description: "Protecting health information", categoryId: "ai_healthcare", questions: [
        Question(id: "ah4_q1", type: .multipleChoice, questionText: "What does HIPAA primarily protect in the context of AI-powered healthcare systems?", options: ["The privacy and security of patient health information", "The accuracy of AI diagnostic predictions", "The licensing requirements for healthcare AI companies", "The intellectual property of AI algorithm designs"], correctAnswer: "The privacy and security of patient health information", explanation: "HIPAA (Health Insurance Portability and Accountability Act) establishes national standards for protecting patient health data, which applies to any AI system that processes, stores, or transmits protected health information."),
        Question(id: "ah4_q2", type: .trueFalse, questionText: "The 2023 Google-Ascension health data partnership controversy highlighted that AI systems processing patient data must comply with data privacy regulations even when the stated goal is improving care.", options: ["True", "False"], correctAnswer: "True", explanation: "The Google-Ascension 'Project Nightingale' controversy revealed that millions of patient records were shared with Google, raising concerns about transparency and consent even though HIPAA technically permitted the arrangement as a business associate agreement."),
        Question(id: "ah4_q3", type: .fillInBlank, questionText: "__________ is the process of removing names, dates, and other personal identifiers from health records before using them to train AI models.", options: ["De-identification", "Encryption", "Tokenization", "Compression"], correctAnswer: "De-identification", explanation: "De-identification strips protected health information of 18 specific identifiers defined by HIPAA, allowing the data to be used for AI research and model training without compromising individual patient privacy."),
        Question(id: "ah4_q4", type: .multipleChoice, questionText: "How does federated learning address privacy concerns when training healthcare AI across multiple hospitals?", options: ["AI models travel to each hospital's data rather than centralizing patient records", "All patient records are uploaded to a single secure government database", "Hospitals share anonymized summaries through encrypted email", "Each hospital trains a completely separate AI with no shared learning"], correctAnswer: "AI models travel to each hospital's data rather than centralizing patient records", explanation: "Federated learning sends the AI model to each hospital where it trains locally on that institution's data. Only model updates, not patient data, are shared back, preserving privacy while enabling collaborative learning across institutions."),
        Question(id: "ah4_q5", type: .scenarioJudgment, questionText: "A health technology startup wants to scrape publicly available patient forum posts to train a mental health AI model without informing the forum users. Is this acceptable?", options: ["No, using health-related personal data without informed consent is ethically problematic", "Yes, publicly posted data has no privacy protections", "Only if the startup anonymizes the data after collection"], correctAnswer: "No, using health-related personal data without informed consent is ethically problematic", explanation: "Even publicly shared health information carries ethical obligations. Individuals sharing on health forums have a reasonable expectation that their posts will not be repurposed for commercial AI training without their knowledge or consent."),
        Question(id: "ah4_q6", type: .multipleChoice, questionText: "Why are synthetic health datasets generated by AI models like MOSTLY AI or Syntegra valuable for healthcare research?", options: ["They preserve the statistical properties of real patient data without exposing actual individuals", "They are always more accurate than real-world clinical data", "They eliminate the need for any real patient data collection", "They cost nothing to generate and require no computational resources"], correctAnswer: "They preserve the statistical properties of real patient data without exposing actual individuals", explanation: "Synthetic data generators create artificial patient records that mirror the distributions and correlations of real datasets, enabling AI researchers to develop and test models without risking patient privacy breaches.")
    ], order: 3, difficulty: .advanced)
    static let lesson5 = LessonData(id: "ah_l5", title: "Mental Health AI", description: "AI for emotional well-being", categoryId: "ai_healthcare", questions: [
        Question(id: "ah5_q1", type: .multipleChoice, questionText: "What can AI-powered mental health platforms like Woebot and Wysa provide to users?", options: ["Evidence-based coping strategies and cognitive behavioral therapy exercises", "Legally binding psychiatric diagnoses and medication prescriptions", "Complete replacement for licensed therapists and counselors", "Guaranteed cures for anxiety, depression, and other conditions"], correctAnswer: "Evidence-based coping strategies and cognitive behavioral therapy exercises", explanation: "Woebot and Wysa deliver structured CBT-based interventions, mood tracking, and coping tools. They serve as accessible first-line support but are designed to complement, not replace, professional therapy."),
        Question(id: "ah5_q2", type: .trueFalse, questionText: "Research suggests AI mental health chatbots are most effective when used as a supplement to professional therapy rather than a standalone replacement.", options: ["True", "False"], correctAnswer: "True", explanation: "Clinical studies show AI chatbots can reduce symptoms of anxiety and depression, but outcomes are best when they complement professional care, providing support between sessions and reinforcing therapeutic techniques."),
        Question(id: "ah5_q3", type: .scenarioJudgment, questionText: "A user tells an AI mental health chatbot that they are having thoughts of self-harm. What should a well-designed AI system do?", options: ["Immediately display crisis hotline numbers and guide the user to emergency resources", "Attempt to provide therapy for the suicidal ideation on its own", "End the conversation to avoid liability", "Tell the user their feelings are not valid and to think positively"], correctAnswer: "Immediately display crisis hotline numbers and guide the user to emergency resources", explanation: "Responsible AI mental health platforms must have robust crisis detection protocols that immediately provide emergency contact information, such as the 988 Suicide and Crisis Lifeline, and encourage users to seek immediate professional help."),
        Question(id: "ah5_q4", type: .fillInBlank, questionText: "AI tools integrated with wearable devices can monitor changes in sleep, activity, and social __________ patterns to detect early warning signs of depression.", options: ["behavior", "media", "dietary", "commute"], correctAnswer: "behavior", explanation: "Platforms combining AI with wearable data analyze behavioral patterns including sleep quality, physical activity levels, and social interaction frequency to identify deviations that may indicate worsening mental health."),
        Question(id: "ah5_q5", type: .multipleChoice, questionText: "What is a key advantage that AI mental health tools like Woebot offer over traditional therapy access?", options: ["Around-the-clock availability and lower barriers related to cost and stigma", "Superior emotional understanding compared to human therapists", "Complete elimination of all data privacy and confidentiality concerns", "Guaranteed effectiveness for all mental health conditions"], correctAnswer: "Around-the-clock availability and lower barriers related to cost and stigma", explanation: "AI mental health tools are available 24/7, cost less than traditional therapy, and some users find it easier to share sensitive feelings with an AI, reducing the stigma barrier that prevents many from seeking help."),
        Question(id: "ah5_q6", type: .multipleChoice, questionText: "What fundamental limitation do all current AI mental health tools share?", options: ["They process language patterns but cannot genuinely understand or empathize with human emotions", "They are significantly more expensive than traditional in-person therapy", "They are clinically proven to be less effective than doing nothing at all", "They cannot process any form of text-based user input"], correctAnswer: "They process language patterns but cannot genuinely understand or empathize with human emotions", explanation: "Current AI systems use pattern recognition and natural language processing to generate helpful responses, but they lack genuine emotional understanding, consciousness, or the lived experience that human therapists bring to the therapeutic relationship.")
    ], order: 4, difficulty: .intermediate)
    static let lesson6 = LessonData(id: "ah_l6", title: "Future of AI in Medicine", description: "What's coming next", categoryId: "ai_healthcare", questions: [
        Question(id: "ah6_q1", type: .multipleChoice, questionText: "How are companies like Tempus and Foundation Medicine using AI to advance personalized medicine?", options: ["Analyzing individual genomic data to tailor cancer treatments to each patient", "Prescribing the same standard treatment protocol to every patient", "Using AI to randomly assign patients to different drug trials", "Replacing oncologists with fully autonomous AI treatment systems"], correctAnswer: "Analyzing individual genomic data to tailor cancer treatments to each patient", explanation: "Tempus and Foundation Medicine use AI to analyze genomic sequencing data alongside clinical records, helping oncologists select targeted therapies matched to each patient's unique tumor profile and genetic makeup."),
        Question(id: "ah6_q2", type: .trueFalse, questionText: "The da Vinci surgical system by Intuitive Surgical has been used in millions of AI-assisted robotic procedures worldwide.", options: ["True", "False"], correctAnswer: "True", explanation: "The da Vinci system has performed over 12 million procedures globally, using AI-enhanced robotics to provide surgeons with greater precision, smaller incisions, and improved visualization during minimally invasive surgery."),
        Question(id: "ah6_q3", type: .matchPairs, questionText: "Match these emerging AI healthcare innovations with their descriptions:", matchPairs: [
            MatchPair(term: "Precision oncology", definition: "Cancer treatment matched to tumor genetics"),
            MatchPair(term: "Digital twins", definition: "Virtual patient models for treatment simulation"),
            MatchPair(term: "Predictive analytics", definition: "Forecasting disease risk before symptoms appear"),
            MatchPair(term: "Surgical robotics", definition: "AI-guided tools for enhanced operative precision")
        ], explanation: "These AI-driven innovations represent the next frontier in healthcare, each addressing different aspects of patient care from prevention through treatment."),
        Question(id: "ah6_q4", type: .fillInBlank, questionText: "AI-powered __________ patient monitoring uses wearable devices like Apple Watch and Fitbit combined with machine learning to track health metrics outside of clinical settings.", options: ["remote", "in-person", "centralized", "acute"], correctAnswer: "remote", explanation: "Remote patient monitoring combines consumer wearables and medical-grade sensors with AI algorithms to continuously track heart rate, blood oxygen, activity, and sleep patterns, alerting healthcare providers to concerning changes."),
        Question(id: "ah6_q5", type: .multipleChoice, questionText: "What is a 'digital twin' in the context of healthcare AI?", options: ["A computational model that simulates an individual patient's biology to test treatments virtually", "An identical twin sibling whose health data is tracked digitally", "A backup copy of a hospital's electronic medical records system", "A second AI algorithm that verifies the first algorithm's diagnosis"], correctAnswer: "A computational model that simulates an individual patient's biology to test treatments virtually", explanation: "Digital twins create personalized virtual models of patients using their health data, allowing physicians and researchers to simulate how different treatments or interventions might affect that specific individual before applying them."),
        Question(id: "ah6_q6", type: .scenarioJudgment, questionText: "A technology executive claims that AI will completely replace all physicians and surgeons within the next decade. How should this claim be evaluated?", options: ["It is highly unrealistic given the complexity of medicine and the need for human judgment", "It is likely accurate because AI technology is advancing exponentially", "It depends entirely on how much funding AI healthcare companies receive"], correctAnswer: "It is highly unrealistic given the complexity of medicine and the need for human judgment", explanation: "While AI will profoundly transform healthcare, medicine requires empathy, ethical judgment, physical examination, and complex decision-making in uncertain situations that current AI cannot replicate. The future is human-AI collaboration, not replacement.")
    ], order: 5, difficulty: .advanced)
}
